module mux2to1_1bit (
    input sel,
    input in0,
    input in1,
    output out
);

    reg obf_mux_out;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: obf_mux_out = in0;
            1'b1: obf_mux_out = in1;
            default: obf_mux_out = 1'b0;  // Default case (should not occur)
        endcase
    end

    assign out = obf_mux_out;

endmodule
